import{_ as l,o as a,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"📊 市場情緒日報 — 2026年5月23日（週六）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-23.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-23.md"}'),e={name:"Deep32Q知識庫/市場情緒/市場情緒_2026-05-23.md"};function r(n,i,s,p,d,h){return a(),t("div",null,[...i[0]||(i[0]=[o('<h1 id="📊-市場情緒日報-—-2026年5月23日-週六" tabindex="-1">📊 市場情緒日報 — 2026年5月23日（週六） <a class="header-anchor" href="#📊-市場情緒日報-—-2026年5月23日-週六" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026年5月23日（週六）&quot;">​</a></h1><p><strong>查詢時間 (TST)</strong>：08:22 | <strong>資料截止</strong>：2026-05-22 收盤 / 2026-05-23 盤前</p><hr><h2 id="🔑-今日最大敘事錨點-美伊戰爭持續-→-荷莫茲海峽封鎖-→-油價飆升-→-全球通膨壓力" tabindex="-1">🔑 今日最大敘事錨點：美伊戰爭持續 → 荷莫茲海峽封鎖 → 油價飆升 → 全球通膨壓力 <a class="header-anchor" href="#🔑-今日最大敘事錨點-美伊戰爭持續-→-荷莫茲海峽封鎖-→-油價飆升-→-全球通膨壓力" aria-label="Permalink to &quot;🔑 今日最大敘事錨點：美伊戰爭持續 → 荷莫茲海峽封鎖 → 油價飆升 → 全球通膨壓力&quot;">​</a></h2><p><strong>核心事件</strong>：2026年2月28日美以對伊朗發動打擊後，伊朗反擊封鎖荷莫茲海峽，全球約1400萬桶/日（14%）石油供應被移除。截至5月23日，伊朗建立「管制海域」收取通行費（最高$200萬/船），EIA預估海峽要到5月底才逐步恢復通航，完全恢復需更久。</p><hr><h2 id="📌-10點重點摘要-tst-08-22查詢" tabindex="-1">📌 10點重點摘要（TST 08:22查詢） <a class="header-anchor" href="#📌-10點重點摘要-tst-08-22查詢" aria-label="Permalink to &quot;📌 10點重點摘要（TST 08:22查詢）&quot;">​</a></h2><h3 id="🔴-重大事件-前3點-深度敘事" tabindex="-1">🔴 重大事件（前3點，深度敘事） <a class="header-anchor" href="#🔴-重大事件-前3點-深度敘事" aria-label="Permalink to &quot;🔴 重大事件（前3點，深度敘事）&quot;">​</a></h3><p><strong>1. 🛢️ 油價飆升：Brent $104 / WTI $97 — 戰爭溢價持續</strong></p><ul><li>Brent原油收於$103.94-$104.70/桶，WTI $96-$97/桶</li><li>較一年前上漲約60%，因荷莫茲海峽封鎖導致全球最大供應中斷</li><li>巴萊克維持2026年Brent均價$100預測，風險偏向上行</li><li>來源：TradingEconomics (2026-05-22), Wikipedia: 2026 Iran War (2026-05-21)</li></ul><p><strong>2. 🇺🇸 美股創新高：道瓊50,579 / S&amp;P 500七連勝週</strong></p><ul><li>道瓇+0.58%至50,579.70創新高，S&amp;P 500+0.37%至7,473.47（第八週連漲）</li><li>納指+0.19%至26,343.97，羅素2000+0.91%至2,869.23領漲</li><li>AI相關個股持續跑贏大盤，NVIDIA強勁財報支撐</li><li>來源：TheStreet (2026-05-22), Motley Fool (2026-05-22)</li></ul><p><strong>3. 🇹🇼 台股創歷史新高：加權指數42,267.97 (+899.76, +2.18%)</strong></p><ul><li>台積電收於NT$2,255 (+NT$25, +1.12%)</li><li>連續5日上漲，半導體板塊領漲</li><li>亞洲市場普遍走高：日股+2.68%至63,339（接近歷史新高），韓股KOSDAQ +5%</li><li>來源：Taiwan News (2026-05-22), Investing.com (2026-05-22)</li></ul><h3 id="🟡-次要事件-中間5點-含具體數值" tabindex="-1">🟡 次要事件（中間5點，含具體數值） <a class="header-anchor" href="#🟡-次要事件-中間5點-含具體數值" aria-label="Permalink to &quot;🟡 次要事件（中間5點，含具體數值）&quot;">​</a></h3><p><strong>4. 💰 美元指數DXY 99.32 — 週收平</strong></p><ul><li>DXY微升0.07%至99.32，月漲0.56%，年漲0.21%</li><li>美元走穩反映Fed維持高利率預期（油價通膨壓力）</li><li>來源：TradingEconomics (2026-05-22)</li></ul><p><strong>5. 📈 美國公債殖利率：10Y 4.56% / 2Y 4.14%</strong></p><ul><li>10年期殖利率較前日下降7.5bp至4.56%</li><li>10年期TIPS實質利率2.16%，5年TIPS 1.65%</li><li>殖利率曲線向上傾斜，3M T-Bill 3.67%</li><li>來源：StreetStats (2026-05-21), TradingEconomics (2026-05-22)</li></ul><p><strong>6. 🪙 黃金小幅回調：XAU/USD ~$4,509</strong></p><ul><li>COMEX 5/22收於$4,530.30 (-0.21%)，OTC現貨約$4,509</li><li>連續兩週下跌，主因美元走強+高油價推升通膨預期→Fed可能更長期維持高利率</li><li>但地緣風險支撐下方，結構性牛市未變</li><li>Goldman Sachs預測2026年底金價$5,400</li><li>來源：TradingEconomics (2026-05-23), Vietnam.vn (2026-05-23)</li></ul><p><strong>7. ₿ 比特幣約$103,000 — 加密市場謹慎均衡</strong></p><ul><li>BTC交易於~$103,000，分析師看好若看漲動能持續可挑戰$150,000</li><li>加密總市值4月上升8%至$2.6兆</li><li>ETH情緒偏空，Fear &amp; Greed指數顯示「恐懼」</li><li>來源：Coinbase Institutional (2026), CoinCodex (2026-05-23)</li></ul><p><strong>8. 🌍 歐洲市場分化：STOXX 50週漲2.99%至5,198</strong></p><ul><li>歐洲受伊朗戰爭能源衝擊+宏觀疲軟制約，AI相關個股持續領漲</li><li>德國DAX盤前下跌0.5%，英國FTSE 100因材料板块表現亮眼</li><li>來源：Morningstar (2026-05-22), Saxo (2026-05-22)</li></ul><h3 id="🟢-前瞻-預告-後2點" tabindex="-1">🟢 前瞻/預告（後2點） <a class="header-anchor" href="#🟢-前瞻-預告-後2點" aria-label="Permalink to &quot;🟢 前瞻/預告（後2點）&quot;">​</a></h3><p><strong>9. ⏳ 荷莫茲海峽恢復通航時程：EIA預估5月底逐步恢復，完全正常化需更久</strong></p><ul><li>美國4/13開始封鎖伊朗石油出口，海上事件已達43起</li><li>約150艘油輪在海峡外錨定等待，通行費高達$200萬/船</li><li>關鍵節點：5月底（EIA預估逐步恢復）、6月（交通量增加）、下半年（接近戰前水平）</li><li>來源：EIA via Wikipedia (2026-05-21), Democracy Now (2026-05-21)</li></ul><p><strong>10. 📅 紀念日假期：美國5/25（週一）休市，期貨周日5/24重開</strong></p><ul><li>部分商品期貨週日即開始交易（週二交易日）</li><li>紀念日假期可能影響流動性，注意週末跳空風險</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TheStreet (2026-05-22): 美股收盤數據</li><li>Motley Fool (2026-05-22): S&amp;P 500八週連漲</li><li>Taiwan News (2026-05-22): 台股加權指數42,267.97</li><li>TradingEconomics (2026-05-22/23): 黃金、美元指數、公債殖利率</li><li>Wikipedia: 2026 Iran War / Strait of Hormuz Crisis (2026-05-21)</li><li>Vietnam.vn (2026-05-23): 黃金現貨價格</li><li>Investing.com (2026-05-22): 亞洲市場</li><li>Coinbase Institutional Research (2026): 加密市場展望</li><li>EIA via Wikipedia: 荷莫茲海峽恢復時程 (2026-05-21)</li><li>Motley Fool / Post-Gazette (2026-05-22): 美股期貨前瞻</li></ol><hr><p><strong>🕐 查詢時間 (TST)</strong>：2026-05-23 08:22 <strong>⚠️ 注意</strong>：5/23（週六）全球股市休市，以上為5/22（週五）收盤數據。期貨於5/24（週日）重開。</p>',35)])])}const g=l(e,[["render",r]]);export{u as __pageData,g as default};
